import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

function generateOTP(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function normalizePhone(phone: string): string {
  let cleaned = phone.replace(/[^\d+]/g, "");
  if (cleaned.startsWith("07")) {
    cleaned = "+263" + cleaned.slice(1);
  } else if (cleaned.startsWith("263") && !cleaned.startsWith("+")) {
    cleaned = "+" + cleaned;
  }
  return cleaned;
}

function isValidZimbabwePhone(phone: string): boolean {
  const normalized = normalizePhone(phone);
  return /^\+263(71|73|77|78)\d{7}$/.test(normalized);
}

async function sendSMS(
  supabase: ReturnType<typeof createClient>,
  phoneNumber: string,
  message: string
): Promise<{ success: boolean; status: string; error?: string; providerResponse?: unknown }> {
  const { data: config, error: configError } = await supabase
    .from("sms_config")
    .select("*")
    .eq("id", "sms_config_singleton")
    .single();

  if (configError || !config) {
    console.error("[SMS] Failed to load SMS config:", configError);
    return { success: false, status: "config_error", error: "SMS configuration not found" };
  }

  if (!config.enabled) {
    console.log("[SMS] SMS service is disabled");
    return { success: true, status: "disabled" };
  }

  if (config.test_mode) {
    console.log("[SMS] TEST MODE - OTP for", phoneNumber, ":", message);
    return { success: true, status: "test_mode" };
  }

  const apiUrl: string = config.api_url;
  const apiKey: string = config.api_key;
  const senderId: string = config.sender_id || "ZimCommute";

  // sms.localhost.co.zw API — try GET with query params first (common for African SMS gateways)
  // Field names: apiKey, senderId, recipient, message  OR  applicationId, password, recipient, message
  // We'll try both formats and log the full response so we can diagnose

  // Attempt 1: POST JSON with { apiKey, senderId, recipient, message }
  const jsonPayload = {
    apiKey,
    senderId,
    recipient: phoneNumber,
    message,
  };

  console.log("[SMS] Sending to", phoneNumber, "via", apiUrl);
  console.log("[SMS] Payload:", JSON.stringify(jsonPayload));

  try {
    const response = await fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(jsonPayload),
    });

    const responseText = await response.text();
    console.log("[SMS] HTTP status:", response.status);
    console.log("[SMS] Response body:", responseText);

    let responseData: Record<string, unknown> = {};
    try {
      responseData = JSON.parse(responseText);
    } catch {
      responseData = { raw: responseText };
    }

    // Surface the full provider response for diagnosis
    if (!response.ok) {
      const errMsg = (responseData.message as string)
        || (responseData.error as string)
        || (responseData.description as string)
        || `HTTP ${response.status}: ${responseText}`;
      console.error("[SMS] Provider HTTP error:", errMsg);
      return {
        success: false,
        status: "provider_error",
        error: errMsg,
        providerResponse: responseData,
      };
    }

    // Provider returned 200 — check body for embedded failure
    const bodyStatus = responseData.status ?? responseData.code ?? responseData.statusCode;
    const isBodyFailure =
      bodyStatus !== undefined &&
      bodyStatus !== "success" &&
      bodyStatus !== "200" &&
      bodyStatus !== 200 &&
      bodyStatus !== "OK" &&
      bodyStatus !== true;

    if (isBodyFailure) {
      const errMsg = (responseData.message as string)
        || (responseData.description as string)
        || (responseData.error as string)
        || responseText;
      console.error("[SMS] Provider body failure:", errMsg, "| Full body:", responseText);
      return {
        success: false,
        status: "provider_error",
        error: errMsg,
        providerResponse: responseData,
      };
    }

    console.log("[SMS] Sent successfully to", phoneNumber);
    return { success: true, status: "sent", providerResponse: responseData };
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error("[SMS] Connection error:", errMsg);
    return { success: false, status: "connection_error", error: errMsg };
  }
}

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  const url = new URL(req.url);
  const path = url.pathname.replace(/^\/otp/, "");

  const supabase = createClient(SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY);

  try {
    const body = await req.json();

    // POST /otp/send or /otp/resend
    if ((path === "/send" || path === "/resend") && req.method === "POST") {
      const { phoneNumber } = body;

      if (!phoneNumber) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number is required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      if (!isValidZimbabwePhone(normalizedPhone)) {
        return new Response(
          JSON.stringify({ success: false, message: "Please enter a valid Zimbabwe phone number" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // Rate limiting: max 3 OTPs per hour per phone
      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000).toISOString();
      const { count } = await supabase
        .from("otp_verifications")
        .select("*", { count: "exact", head: true })
        .eq("phone_number", normalizedPhone)
        .gte("created_at", oneHourAgo);

      if ((count ?? 0) >= 3) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many OTP requests. Please wait 1 hour before trying again." }),
          { status: 429, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      // Generate OTP
      const otp = generateOTP();
      const expiresAt = new Date(Date.now() + 5 * 60 * 1000).toISOString();

      // Delete any existing unverified OTPs for this phone
      await supabase
        .from("otp_verifications")
        .delete()
        .eq("phone_number", normalizedPhone)
        .eq("verified", false);

      // Store new OTP
      const { error: insertError } = await supabase
        .from("otp_verifications")
        .insert({
          phone_number: normalizedPhone,
          otp,
          expires_at: expiresAt,
          verified: false,
          attempts: 0,
        });

      if (insertError) {
        console.error("[OTP] Failed to store OTP:", insertError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to generate OTP. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      console.log("[OTP] Generated for", normalizedPhone);

      // Send SMS
      const smsMessage = `Your ZimCommute verification code is: ${otp}. Valid for 5 minutes. Do not share this code.`;
      const smsResult = await sendSMS(supabase, normalizedPhone, smsMessage);

      if (!smsResult.success) {
        console.error("[OTP] SMS delivery failed:", smsResult.status, smsResult.error);
        // Return 500 so the frontend knows SMS genuinely failed — surface the real error
        return new Response(
          JSON.stringify({
            success: false,
            message: smsResult.error
              ? `SMS failed: ${smsResult.error}`
              : "SMS delivery failed. Please check your number and try again.",
            smsStatus: smsResult.status,
            smsError: smsResult.error,
            providerResponse: smsResult.providerResponse,
          }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      return new Response(
        JSON.stringify({
          success: true,
          message: "OTP sent successfully",
          expiresIn: 300,
          smsStatus: smsResult.status,
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // POST /otp/verify
    if (path === "/verify" && req.method === "POST") {
      const { phoneNumber, otp } = body;

      if (!phoneNumber || !otp) {
        return new Response(
          JSON.stringify({ success: false, message: "Phone number and OTP are required" }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const normalizedPhone = normalizePhone(phoneNumber);

      const { data: otpRecord, error: otpError } = await supabase
        .from("otp_verifications")
        .select("*")
        .eq("phone_number", normalizedPhone)
        .eq("verified", false)
        .order("created_at", { ascending: false })
        .limit(1)
        .single();

      if (otpError || !otpRecord) {
        return new Response(
          JSON.stringify({ success: false, message: "No pending OTP found. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (new Date(otpRecord.expires_at) < new Date()) {
        return new Response(
          JSON.stringify({ success: false, message: "OTP has expired. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      if (otpRecord.attempts >= 5) {
        return new Response(
          JSON.stringify({ success: false, message: "Too many failed attempts. Please request a new code." }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ attempts: otpRecord.attempts + 1 })
        .eq("id", otpRecord.id);

      if (otpRecord.otp !== otp.toString()) {
        const remaining = 5 - (otpRecord.attempts + 1);
        return new Response(
          JSON.stringify({
            success: false,
            message: `Invalid code. ${remaining > 0 ? `${remaining} attempts remaining.` : "Please request a new code."}`,
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      await supabase
        .from("otp_verifications")
        .update({ verified: true })
        .eq("id", otpRecord.id);

      const { data: user, error: userError } = await supabase
        .from("users")
        .upsert(
          { phone_number: normalizedPhone, updated_at: new Date().toISOString() },
          { onConflict: "phone_number", ignoreDuplicates: false }
        )
        .select()
        .single();

      if (userError || !user) {
        console.error("[OTP] Failed to upsert user:", userError);
        return new Response(
          JSON.stringify({ success: false, message: "Failed to create user account. Please try again." }),
          { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }

      const token = `user_${user.id}`;
      console.log("[OTP] Verified for", normalizedPhone, "user:", user.id);

      return new Response(
        JSON.stringify({
          success: true,
          token,
          user: {
            id: user.id,
            phoneNumber: user.phone_number,
            fullName: user.full_name,
            email: user.email,
            profilePhotoUrl: user.profile_photo_url,
            userType: user.user_type,
            homeCity: user.home_city,
            verificationLevel: user.verification_level,
            role: user.role,
            walletBalance: user.wallet_balance,
            isBanned: user.is_banned,
            banReason: user.ban_reason,
            createdAt: user.created_at,
            updatedAt: user.updated_at,
          },
        }),
        { status: 200, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    return new Response(
      JSON.stringify({ success: false, message: "Not found" }),
      { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (err: unknown) {
    const errMsg = err instanceof Error ? err.message : String(err);
    console.error("[OTP] Unhandled error:", errMsg);
    return new Response(
      JSON.stringify({ success: false, message: "Internal server error" }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

const SUPABASE_URL = Deno.env.get("SUPABASE_URL")!;
const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY")!;

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type",
  "Access-Control-Allow-Methods": "POST, OPTIONS",
};

function generateOTP(): string {
  return Math.floor(100000 + Math.random() * 900000).toString();
}

function normalizePhone(phone: string): string {
  let cleaned = phone.replace(/[^\d+]/g, "");
  if (cleaned.startsWith("07")) {
    cleaned = "+263" + cleaned.slice(1);
  } else if (cleaned.startsWith("263") && !cleaned.startsWith("+")) {
    cleaned = "+" + cleaned;
  }
  return cleaned;
}

function isValidZimbabwePhone(phone: string): boolean {
  const normalized = normalizePhone(phone);
  return /^\+263(71|73|77|78)\d{7}$/.test(normalized);
}

// Strip leading + for providers that want plain international format
function msisdn(phone: string): string {
  return phone.startsWith("+") ? phone.slice(1) : phone;
}

interface SmsAttemptResult {
  format: string;
  httpStatus: number;
  body: string;
  parsed: Record<string, unknown>;
  success: boolean;
}

async function probeSmsFormats(
  apiUrl: string,
  apiKey: string,
  senderId: string,
  phoneNumber: string,
  message: string
): Promise<{ success: boolean; winningFormat?: string; attempts: SmsAttemptResult[]; error?: string }> {
  const recipient = msisdn(phoneNumber); // e.g. 263773616818
  const attempts: SmsAttemptResult[] = [];

  // Helper: run one attempt and record result
  async function attempt(
    label: string,
    fetchFn: () => Promise<Response>
  ): Promise<SmsAttemptResult> {
    try {
      const res = await fetchFn();
      const bodyText = await res.text();
      console.log(`[SMS][${label}] HTTP ${res.status} | Body: ${bodyText}`);
      let parsed: Record<string, unknown> = {};
      try { parsed = JSON.parse(bodyText); } catch { parsed = { raw: bodyText }; }
      // Determine success: HTTP 2xx AND no embedded failure signal
      const bodyStatus = parsed.status ?? parsed.code ?? parsed.statusCode ?? parsed.Status;
      const bodyOk = bodyStatus === undefined
        || bodyStatus === "success" || bodyStatus === "Success"
        || bodyStatus === "200" || bodyStatus === 200
        || bodyStatus === "OK" || bodyStatus === true
        || bodyStatus === "SENT" || bodyStatus === "sent";
      const success = res.ok && bodyOk;
      return { format: label, httpStatus: res.status, body: bodyText, parsed, success };
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      console.log(`[SMS][${label}] Connection error: ${msg}`);
      return { format: label, httpStatus: 0, body: msg, parsed: { error: msg }, success: false };
    }
  }

  // ── Format 1: POST JSON { apiKey, senderId, recipient, message } ──────────
  attempts.push(await attempt("F1_POST_JSON_apiKey", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ apiKey, senderId, recipient, message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F1_POST_JSON_apiKey", attempts };

  // ── Format 2: POST JSON { applicationId, senderId, recipient, message } ───
  attempts.push(await attempt("F2_POST_JSON_applicationId", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ applicationId: apiKey, senderId, recipient, message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F2_POST_JSON_applicationId", attempts };

  // ── Format 3: POST JSON { apiKey, senderId, msisdn, msg } ─────────────────
  attempts.push(await attempt("F3_POST_JSON_msisdn_msg", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ apiKey, senderId, msisdn: recipient, msg: message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F3_POST_JSON_msisdn_msg", attempts };

  // ── Format 4: POST JSON { applicationId, senderId, msisdn, msg } ──────────
  attempts.push(await attempt("F4_POST_JSON_appId_msisdn_msg", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ applicationId: apiKey, senderId, msisdn: recipient, msg: message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F4_POST_JSON_appId_msisdn_msg", attempts };

  // ── Format 5: POST form-encoded { apiKey, senderId, recipient, message } ──
  attempts.push(await attempt("F5_POST_FORM_apiKey", () => {
    const params = new URLSearchParams({ apiKey, senderId, recipient, message });
    return fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: params.toString(),
    });
  }));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F5_POST_FORM_apiKey", attempts };

  // ── Format 6: POST form-encoded { applicationId, senderId, msisdn, msg } ──
  attempts.push(await attempt("F6_POST_FORM_appId_msisdn", () => {
    const params = new URLSearchParams({ applicationId: apiKey, senderId, msisdn: recipient, msg: message });
    return fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: params.toString(),
    });
  }));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F6_POST_FORM_appId_msisdn", attempts };

  // ── Format 7: GET with query params { apiKey, senderId, recipient, message } 
  attempts.push(await attempt("F7_GET_apiKey", () => {
    const u = new URL(apiUrl);
    u.searchParams.set("apiKey", apiKey);
    u.searchParams.set("senderId", senderId);
    u.searchParams.set("recipient", recipient);
    u.searchParams.set("message", message);
    return fetch(u.toString(), { method: "GET" });
  }));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F7_GET_apiKey", attempts };

  // ── Format 8: GET with query params { applicationId, senderId, msisdn, msg }
  attempts.push(await attempt("F8_GET_appId_msisdn", () => {
    const u = new URL(apiUrl);
    u.searchParams.set("applicationId", apiKey);
    u.searchParams.set("senderId", senderId);
    u.searchParams.set("msisdn", recipient);
    u.searchParams.set("msg", message);
    return fetch(u.toString(), { method: "GET" });
  }));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F8_GET_appId_msisdn", attempts };

  // ── Format 9: POST JSON { api_key, sender_id, to, message } ───────────────
  attempts.push(await attempt("F9_POST_JSON_api_key_to", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ api_key: apiKey, sender_id: senderId, to: recipient, message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F9_POST_JSON_api_key_to", attempts };

  // ── Format 10: POST JSON { token, from, to, text } ────────────────────────
  attempts.push(await attempt("F10_POST_JSON_token_from_to_text", () =>
    fetch(apiUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ token: apiKey, from: senderId, to: recipient, text: message }),
    })
  ));
  if (attempts[attempts.length - 1].success) return { success: true, winningFormat: "F10_POST_JSON_token_from_to_text", attempts };

  // All failed — return all attempt details for diagnosis
  const lastError = attempts[attempts.length - 1];
  const errorSummary = attempts
    .map(a => `${a.format}: HTTP ${a.httpStatus} → ${a.body.slice(0, 120)}`)
    .join(" | ");
  return { success: false, attempts, error: errorSummary };
}

async function sendSMS(
  supabase: ReturnType<typeof createClient>,
  phoneNumber: string,
  message: string
): Promise<{ success: boolean; status: string; error?: string; winningFormat?: string; attempts?: SmsAttemptResult[] }> {
  const { data: config, error: configError } = await supabase
    .from("sms_config")
    .select("*")
    .eq("id", "sms_config_singleton")
    .single();

  if (configError || !config) {
    console.error("[SMS] Failed to load SMS config:", configError);
    return { success: false, status: "config_error", error: "SMS configuration not found" };
  }

  if (!config.enabled) {
    console.log("[SMS] SMS service is disabled");
    return { success: true, status: "disabled" };
  }

  if (config.test_mode) {
    console.log("[SMS] TEST MODE - OTP for", phoneNumber, ":", message);
    return { success: true, status: "test_mode" };
  }

  const apiUrl: string = config.api_url;
  const apiKey: string = config.api_key;
  const senderId: string = config.sender_id || "ZimCommute";

  console.log("[SMS] Probing formats for", phoneNumber, "via", apiUrl);

  const result = await probeSmsFormats(apiUrl, apiKey, senderId, phoneNumber, message);

  // Persist the probe summary to sms_config for easy inspection via SQL
  const diagSummary = result.attempts
    .map(a => `${a.format}:HTTP${a.httpStatus}:${a.body.slice(0, 200)}`)
    .join(" || ");
  await supabase
    .from("sms_config")
    .update({ last_probe_result: diagSummary, updated_at: new Date().toISOString() })
    .eq("id", "sms_config_singleton");

  if (result.success) {
    console.log("[SMS] Success with format:", result.winningFormat);
    return { success: true, status: "sent", winningFormat: result.winningFormat };
  }

  console.error("[SMS] All formats failed. Summary:", result.error);
  return {
    success: false,
    status: "provider_error",
    error: result.error,
    attempts: result.attempts,
  };
}

